Wait, but I'm calling `done()` inside the abort callback AND in the timeout. Let me clean this up:

```typescript
import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap", () => {
  it("should call abort callback when source responds to data read after abort is called while not busy", (done) => {
    let pendingDataCb: Function | null = null;
    let pendingAbortCb: Function | null = null;
    let pendingMapCb: Function | null = null;

    const source = (abort: any, cb: Function) => {
      if (abort) {
        pendingAbortCb = cb;
      } else {
        pendingDataCb = cb;
      }
    };

    const mapper = (data: any, cb: Function) => {
      pendingMapCb = cb;
    };

    const through = asyncMap(mapper);
    const stream = through(source);

    // Start a data read - source holds, busy = false
    stream(null, () => {});

    // Abort while not busy
    const abortError = new Error("abort");
    stream(abortError, (err: any) => {
      expect(err).toBe(abortError);
      done();
    });

    // Source responds to data read AFTER abort - makes busy = true
    if (pendingDataCb) pendingDataCb(null, 42);

    // Source responds to abort
