    let abortResult: any = null;
    stream(abortErr, (err: any) => { abortResult = err; });
    expect(capturedAbortHandler).not.toBeNull();

    // Step 4: Start another read - source delivers sync, mapper holds, busy=true
    stream(null, () => {});
    expect(mapperCb).not.toBeNull();

    // Step 5: Call abort handler while busy=true
    // Original fn1: cb(abort) -> abortResult=abortErr
    // Mutated fn2: if(busy) -> true -> abortCb=cb -> abortResult stays null
    capturedAbortHandler!(abortErr);

    // Step 6: Complete mapper
    // Mutated: aborted=undefined -> cb(null,data) called, abortCb never called
    mapperCb!(null, 2);

    expect(abortResult).toBe(abortErr);
  });
});
```

This avoids the held-data-callback issue entirely! The source always delivers synchronously, so `mapperCb` is always set after `stream(null, ...)`. The key is step 4: after aborting, I start another read to make `busy=true`, then call the captured abort handler.

```typescript
import asyncMap from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/async-map.js";

describe("asyncMap", () => {
  it("abort handler calls cb regardless of busy state when aborting non-busy stream", () => {
    let capturedAbortHandler: Function | null = null;
    let mapperCb: Function | null = null;
    let dataCount = 0;

    const source = (abort: any, cb: Function) => {
      if (abort) {
        capturedAbortHandler = cb;
      } else {
        cb(null, ++dataCount);
      }
    };

    const mapper = (data: any, cb: Function) => {
      mapperCb = cb;
    };

    const stream = asyncMap(mapper)(source);

    stream(null, () => {});
    expect(mapperCb).not.toBeNull();
    mapperCb!(null, 1);
    mapperCb = null;

    const abortErr = new Error("abort");
    let abortResult: any = null;
    stream(abortErr, (err: any) => { abortResult = err; });
    expect(capturedAbortHandler).not.toBeNull();

    stream(null, () => {});
    expect(mapperCb).not.toBeNull();

    capturedAbortHandler!(abortErr);
    mapperCb!(null, 2);

    expect(abortResult).toBe(abortErr);
  });
});
```
